#include <iostream>
#include <vector>
using namespace std;

int main() {
  vector<int> nums;

  for (int i = 1; i <= 5; i++) {
    nums.push_back(i * 10);
  }

  cout << "Elements: ";
  for (size_t i = 0; i < nums.size(); i++) {
    cout << nums[i] << " ";
  }
  cout << endl;

  cout << "Size: " << nums.size() << ", Capacity: " << nums.capacity() << endl;
  return 0;
}
